Class NameValidator Extends %RegisteredObject
{
    /// Check if name is unique in list
    ClassMethod IsNameUnique(name As %String, existingNames As %ListOfDataTypes) As %Boolean
    {
        // BUGGY: Returns wrong boolean value
        For i=1:1:existingNames.Count() {
            If (existingNames.GetAt(i) = name) {
                Quit 1  // Should return 0 (not unique) but returns 1
            }
        }
        Quit 0  // Should return 1 (unique) but returns 0
    }
}

