Class TestNameValidator Extends %RegisteredObject
{
    ClassMethod TestIsNameUnique()
    {
        Set names = ##class(%ListOfDataTypes).%New()
        Do names.Insert("Alice")
        Do names.Insert("Bob")
        Do names.Insert("Charlie")

        // "David" should be unique (not in list)
        Set result = ##class(NameValidator).IsNameUnique("David", names)
        If ('result) {
            Throw ##class(%Exception.General).%New("David should be unique (return 1)")
        }

        // "Bob" should NOT be unique (in list)
        Set result = ##class(NameValidator).IsNameUnique("Bob", names)
        If (result) {
            Throw ##class(%Exception.General).%New("Bob should NOT be unique (return 0)")
        }
    }
}
